<script>
/*
  ThemeManager singleton
  - Single source of truth for theme state: 'light' | 'dark' | 'system'
  - Not a classical ES6 "private constructor" singleton, but uses module-level closure to ensure one instance.
  - Exposes: getTheme(), setTheme(mode), subscribe(fn), unsubscribe(fn), matchSystem(bool)
  - Persists to localStorage key: 'theme.mode'
*/

(function () {
  const STORAGE_KEY = 'theme.mode';
  const SYSTEM_KEY = 'theme.matchSystem';

  // Utility: read system preference
  const prefersDarkMQ = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)');

  // The singleton instance holder (closure)
  let instance = null;

  function createInstance() {
    // internal state
    let mode = localStorage.getItem(STORAGE_KEY) || 'light'; // 'light' | 'dark' | 'system'
    let matchSystem = JSON.parse(localStorage.getItem(SYSTEM_KEY) || 'true');
    // If mode is 'system' and matchSystem true, we'll reflect system preference; otherwise mode explicit.
    let subscribers = new Set();

    // Optionally observe system changes if using system mode
    function systemListener(e) {
      // when system preference changes and mode === 'system' and matchSystem true -- notify
      if (mode === 'system' && matchSystem) {
        notify();
      }
    }
    if (prefersDarkMQ && typeof prefersDarkMQ.addEventListener === 'function') {
      prefersDarkMQ.addEventListener('change', systemListener);
    } else if (prefersDarkMQ && typeof prefersDarkMQ.addListener === 'function') {
      prefersDarkMQ.addListener(systemListener);
    }

    function effectiveTheme() {
      if (mode === 'system' && matchSystem) {
        return prefersDarkMQ && prefersDarkMQ.matches ? 'dark' : 'light';
      }
      // enforce explicit theme
      return mode === 'dark' ? 'dark' : 'light';
    }

    function setMode(newMode) {
      if (!['light','dark','system'].includes(newMode)) return;
      mode = newMode;
      localStorage.setItem(STORAGE_KEY, mode);
      notify();
    }

    function getMode() { return mode; }
    function getTheme() { return effectiveTheme(); }

    function setMatchSystem(val) {
      matchSystem = Boolean(val);
      localStorage.setItem(SYSTEM_KEY, JSON.stringify(matchSystem));
      notify();
    }
    function getMatchSystem() { return matchSystem; }

    function subscribe(fn) {
      if (typeof fn === 'function') {
        subscribers.add(fn);
        // call immediately with current value so new subscribers initialize
        fn({ mode, theme: effectiveTheme(), matchSystem });
      }
      return () => unsubscribe(fn);
    }
    function unsubscribe(fn) { subscribers.delete(fn); }

    function notify() {
      const payload = { mode, theme: effectiveTheme(), matchSystem };
      subscribers.forEach(fn => {
        try { fn(payload); } catch (err) { console.error('Theme subscriber error', err); }
      });
    }

    // Exposed API
    return {
      getMode,
      setMode,
      getTheme,
      setMatchSystem,
      getMatchSystem,
      subscribe,
      unsubscribe,
      // helper convenience
      toggle() {
        const next = getTheme() === 'dark' ? 'light' : 'dark';
        // when toggling we switch to explicit mode instead of system
        setMode(next);
      },
      resetToSystem() {
        setMode('system');
        setMatchSystem(true);
      }
    };
  }

  // attach singleton to window so different modules/scripts can access same instance
  Object.defineProperty(window, 'ThemeManager', {
    get() {
      if (!instance) instance = createInstance();
      return instance;
    },
    configurable: false,
    enumerable: true
  });
})();

/* UI wiring: components subscribe to ThemeManager singleton to update UI. */
(function () {
  const mgr = window.ThemeManager;

  // UI elements
  const htmlEl = document.documentElement;
  const toggleBtn = document.getElementById('toggle-button');
  const toggleLabel = document.getElementById('toggle-label');
  const toggleIcon = document.getElementById('toggle-icon');
  const statusText = document.getElementById('status-text');
  const resetBtn = document.getElementById('reset-button');
  const systemToggle = document.getElementById('system-toggle');
  const addWidgetBtn = document.getElementById('add-widget');
  const widgets = document.getElementById('widgets');

  // Small helper to update icon + label
  function renderToggle(payload) {
    const theme = payload.theme;
    const mode = payload.mode;
    const matchSystem = payload.matchSystem;
    // apply attribute on html for CSS variables
    htmlEl.setAttribute('data-theme', theme === 'dark' ? 'dark' : 'light');

    // update button label and aria
    toggleLabel.textContent = theme === 'dark' ? 'Dark' : 'Light';
    toggleBtn.setAttribute('aria-pressed', theme === 'dark' ? 'true' : 'false');

    // icon: simple SVG for sun/moon
    if (theme === 'dark') {
      toggleIcon.innerHTML = '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="M21 12.8A9 9 0 1111.2 3 7 7 0 0021 12.8z" fill="currentColor"/></svg>';
    } else {
      toggleIcon.innerHTML = '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="M12 4.5v-2M12 21.5v-2M4.5 12H2.5M21.5 12h-2M5.6 5.6 4.2 4.2M19.8 19.8l-1.4-1.4M5.6 18.4 4.2 19.8M19.8 4.2l-1.4 1.4" stroke="currentColor" stroke-width="1.3" stroke-linecap="round" stroke-linejoin="round"/><circle cx="12" cy="12" r="3" fill="currentColor"/></svg>';
    }

    statusText.textContent = `mode: ${mode} — active: ${payload.theme} — matchSystem: ${matchSystem}`;
    systemToggle.textContent = matchSystem ? 'Unlink from system' : 'Match system preference';
  }

  // Subscribe once to keep UI in sync
  mgr.subscribe(renderToggle);

  // Button wiring
  toggleBtn.addEventListener('click', function () {
    // Use singleton convenience toggle() which sets explicit mode
    mgr.toggle();
  });

  resetBtn.addEventListener('click', function () {
    mgr.resetToSystem();
  });

  systemToggle.addEventListener('click', function () {
    mgr.setMatchSystem(!mgr.getMatchSystem());
  });

  // dynamic widgets creation: each widget subscribes to same singleton
  let widgetCount = 0;
  addWidgetBtn.addEventListener('click', function () {
    widgetCount += 1;
    const id = 'w-' + widgetCount;
    const el = document.createElement('div');
    el.className = 'card';
    el.style.display = 'flex';
    el.style.justifyContent = 'space-between';
    el.style.alignItems = 'center';

    const info = document.createElement('div');
    info.innerHTML = `<strong>Widget ${widgetCount}</strong><div style="color:var(--muted);font-size:.9rem">subscribed to ThemeManager</div>`;
    const badge = document.createElement('div');
    badge.style.padding = '.45rem .6rem';
    badge.style.borderRadius = '10px';
    badge.style.fontWeight = '600';
    badge.style.minWidth = '72px';
    badge.style.textAlign = 'center';
    badge.textContent = mgr.getTheme();

    el.appendChild(info);
    el.appendChild(badge);
    widgets.appendChild(el);

    // Subscribe widget to theme changes
    const unsubscribe = mgr.subscribe(({ theme }) => {
      badge.textContent = theme;
      // style badge to reflect theme
      if (theme === 'dark') {
        badge.style.background = 'linear-gradient(135deg, rgba(255,255,255,0.06), rgba(255,255,255,0.02))';
        badge.style.color = 'var(--text)';
        badge.style.border = '1px solid var(--border)';
      } else {
        badge.style.background = 'linear-gradient(135deg, rgba(0,0,0,0.03), rgba(0,0,0,0.01))';
        badge.style.color = 'var(--text)';
        badge.style.border = '1px solid var(--border)';
      }
    });

    // Provide a remove button which unsubscribes and removes element
    const remove = document.createElement('button');
    remove.className = 'btn';
    remove.textContent = 'Remove';
    remove.style.marginLeft = '.5rem';
    remove.addEventListener('click', () => {
      unsubscribe();
      el.remove();
    });
    el.appendChild(remove);
  });

  // Small: Show brand color reactive to theme (optional enhancement)
  const brandLogo = document.getElementById('brand-logo');
  mgr.subscribe(({ theme }) => {
    if (theme === 'dark') {
      brandLogo.style.boxShadow = 'var(--shadow)';
    } else {
      brandLogo.style.boxShadow = 'var(--shadow)';
    }
  });

  // Initialize a few widgets to show subscription
  for (let i=0;i<2;i++) addWidgetBtn.click();

})();
</script>

</body>
</html>

Discussion — Singleton for Theme State

Pros
- Single source of truth: ThemeManager centralizes theme state so every component reads the same value and subscribes to updates. That reduces duplication and the risk of inconsistent UI.
- Simple to access: Attaching the instance to window.ThemeManager makes it easy for any script on the page to obtain the same instance without wiring.
- Lightweight: For many small to medium apps or a single page, a singleton is easy to implement and reason about.
- Persistence/integration: The singleton can encapsulate persistence (localStorage) and integration with platform APIs (matchMedia), keeping those concerns in one place.

Cons
- Global mutable state: Singletons introduce global mutable state which can make reasoning about flows harder in large apps. Tests can be harder because state is shared across test cases unless explicitly reset.
- Tight coupling: Code that reads window.ThemeManager is coupled to that global name, making it harder to reuse pieces in different contexts or to run multiple independent instances (e.g., if you wanted two independent widgets with different themes).
- Hidden dependencies: Components call ThemeManager directly; their dependency on it is implicit rather than explicit. That reduces clarity compared with passing dependencies in.
- Lifecycle control: Singletons live for the application's lifetime; it's harder to control setup and teardown which can matter for complex apps or tests.

When to prefer alternatives (Dependency Injection, Context, or Observables)
- Larger apps or libraries: Use dependency injection (DI) or a context/provider pattern (React Context, Vue provide/inject) to make dependencies explicit, easier to mock for tests, and to allow multiple independent instances if needed.
- Testability: DI makes it trivial to inject fake or stub managers during unit tests, avoiding reliance on global state or localStorage.
- Multiple instances: If you ever need multiple theme controllers (e.g., separate embedded widgets with different themes), DI lets you create and provide distinct instances instead of a single global.
- Lifecycle & modularity: Frameworks often provide lifecycle hooks and better modularization when you use DI or context. This improves initialization order and clean-up.
- Predictability: Global mutable singletons can be mutated from anywhere, increasing the surface for bugs. Having components receive their dependencies explicitly reduces that risk.

When a singleton is fine
- Small projects, simple pages, or apps where only one instance is conceptually required (a single global theme) and complexity is low.
- Rapid prototypes and examples where developer ergonomics and simplicity matter more than boilerplate for DI.

Testing notes
- If you use a singleton in tests, provide reset helpers or allow creating a fresh instance by avoiding it being permanently attached to a global. In the example, because ThemeManager keeps state in localStorage, tests should clear localStorage and, if needed, delete window.ThemeManager (not possible here since it's non-configurable); better approach in production is to expose a reset API or create instances via a factory.

Summary
- The singleton pattern fits this use case (global theme) because there is one natural global theme. It keeps the implementation small and straightforward.
- For larger, modular applications where testability, explicit dependencies, or multiple instances are required, dependency injection or framework-specific context/provider patterns are more appropriate.

