  <script>
    /****************************************************************
     * ThemeManager singleton
     *
     * Responsibilities:
     * - Hold current theme ("light" | "dark")
     * - Persist to localStorage
     * - Allow listeners to subscribe/unsubscribe to changes
     * - Provide a single global access point
     ****************************************************************/
    const ThemeManager = (function(){
      let instance = null;

      function createInstance(){
        // private state
        const STORAGE_KEY = 'theme_pref_v1';
        let theme = (localStorage.getItem(STORAGE_KEY) || 'light');
        if(theme !== 'dark') theme = 'light'; // sanitize
        const listeners = new Set();

        function applyThemeToDocument() {
          if(theme === 'dark') {
            document.documentElement.classList.add('theme-dark');
          } else {
            document.documentElement.classList.remove('theme-dark');
          }
          // update DOM elements that aren't dynamic via CSS vars
          const label = document.getElementById('toggleLabel');
          const dot = document.getElementById('toggleDot');
          if(label) label.textContent = theme[0].toUpperCase() + theme.slice(1);
          if(dot) dot.style.transform = theme === 'dark' ? 'translateX(14px)' : 'translateX(0)';
          // persist
          localStorage.setItem(STORAGE_KEY, theme);
          const persistInfo = document.getElementById('persistInfo');
          if(persistInfo) persistInfo.textContent = 'Saved: ' + theme;
        }

        function notify(){
          applyThemeToDocument();
          listeners.forEach(fn => { try { fn(theme); } catch(e){ console.error(e); } });
        }

        return {
          getTheme(){
            return theme;
          },
          setTheme(newTheme){
            if(newTheme !== 'light' && newTheme !== 'dark') return;
            if(theme === newTheme) return;
            theme = newTheme;
            notify();
          },
          toggle(){
            this.setTheme(theme === 'dark' ? 'light' : 'dark');
          },
          subscribe(fn){
            listeners.add(fn);
            // call immediately with current
            try{ fn(theme); }catch(e){console.error(e)}
            return () => listeners.delete(fn);
          },
          _clearStorage(){
            localStorage.removeItem(STORAGE_KEY);
          }
        };
      }

      return {
        getInstance(){
          if(!instance) instance = createInstance();
          return instance;
        }
      };
    })();

    /****************************************************************
     * Initialization wiring (acts like UI layer components)
     ****************************************************************/
    (function(){
      const tm = ThemeManager.getInstance();

      // Wire top-level toggle
      const toggle = document.getElementById('themeToggle');
      if(toggle){
        toggle.addEventListener('click', () => tm.toggle());
      }

      // Sample action button uses styling; shows singleton is accessible
      document.getElementById('sampleAction').addEventListener('click', () => {
        alert('Sample action (UI element) — current theme: ' + tm.getTheme());
      });

      // Accent color selection adjusts CSS variable directly (not part of singleton)
      const accentSelect = document.getElementById('accentSelect');
      accentSelect.addEventListener('change', (e) => {
        const val = e.target.value;
        document.documentElement.style.setProperty('--accent', val);
      });

      // Clear persisted theme
      document.getElementById('clearPersist').addEventListener('click', () => {
        tm._clearStorage();
        document.getElementById('persistInfo').textContent = 'Cleared. Reload to reapply defaults.';
      });

      // Buttons to demonstrate visual change
      document.getElementById('btnPrimary').addEventListener('click', () => alert('Primary clicked'));
      document.getElementById('btnSecondary').addEventListener('click', () => alert('Secondary clicked'));

      // Apply initial theme to document (singleton handles persistence)
      // subscribe only to make sure DOM labels + persisted info are updated
      tm.subscribe(() => { /* no-op: subscribe triggers applyThemeToDocument and updates */ });

      // Component A: subscribes and can request theme toggle
      (function ComponentA(){
        const status = document.getElementById('compAState');
        const btn = document.getElementById('compAChange');
        // subscribe to theme changes
        const unsub = tm.subscribe((theme) => {
          if(status) status.textContent = 'State: ' + theme;
          // illustrate that component-specific UI can adjust beyond CSS vars
          if(btn) btn.textContent = theme === 'dark' ? 'Switch to Light' : 'Toggle to Dark';
        });
        btn.addEventListener('click', () => tm.toggle());
        // optional cleanup demo (not used here):
        // window.addEventListener('unload', unsub);
      })();

      // Component B: set via select; demonstrates same instance observed
      (function ComponentB(){
        const status = document.getElementById('compBState');
        const select = document.getElementById('compBSelect');
        const unsub = tm.subscribe((theme) => {
          if(status) status.textContent = 'State: ' + theme;
          if(select) select.value = theme;
        });
        select.addEventListener('change', (e) => {
          tm.setTheme(e.target.value);
        });
      })();

      // Optional: keyboard shortcut 'T' toggles theme
      window.addEventListener('keydown', (e) => {
        if(e.key.toLowerCase() === 't' && !/input|textarea|select/i.test(document.activeElement.tagName)){
          e.preventDefault();
          tm.toggle();
        }
      });

      // Example of late-acquired component: created after 2 seconds
      setTimeout(() => {
        const late = document.createElement('div');
        late.className = 'small-card';
        late.style.marginTop = '12px';
        late.innerHTML = '<h4>Late Component</h4><p class="note">I subscribed after initial render.</p>';
        document.querySelector('.cards').appendChild(late);
        ThemeManager.getInstance().subscribe((theme) => {
          // change background slightly to show reaction
          late.style.background = theme === 'dark' ? 'linear-gradient(180deg, rgba(255,255,255,0.02), transparent)' : 'linear-gradient(180deg, rgba(0,0,0,0.02), transparent)';
        });
      }, 2000);

    })();
  </script>
</body>
