  <script>
    /*****************************************************************************
     * ThemeManager Singleton
     *
     * Features:
     * - getInstance(): returns the single ThemeManager instance.
     * - getTheme(): returns 'light' or 'dark'.
     * - setTheme(theme): sets theme and notifies subscribers.
     * - subscribe(fn): register listener(fn(theme)) -> returns unsubscribe function.
     * - setPersistence(mode): 'none' or 'local', controls whether to save to localStorage.
     * - resetToSystem(): apply system preference.
     *
     * Implementation note: we use an IIFE to create a closure and ensure only one
     * instance can be created. Consumers call ThemeManager.getInstance().
     *****************************************************************************/

    const ThemeManager = (function () {
      // Private variables inside closure
      let instance = null;

      // Constructor for the singleton
      function createInstance() {
        // Defaults
        let theme = 'light';
        let persistence = 'none'; // 'none' | 'local'
        const subscribers = new Set();

        const STORAGE_KEY = 'theme-manager:theme';

        // detect system preference
        const mql = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)');

        function applyTheme(t) {
          document.documentElement.setAttribute('data-theme', t);
          theme = t;
          subscribers.forEach(fn => {
            try { fn(t); } catch (e) { console.error('Subscriber error', e); }
          });
        }

        function loadFromStorage() {
          try {
            const saved = localStorage.getItem(STORAGE_KEY);
            if (saved === 'dark' || saved === 'light') {
              return saved;
            }
          } catch (e) {
            // ignoring storage errors
          }
          return null;
        }

        // Initialize: check storage if available
        const stored = loadFromStorage();
        if (stored) {
          theme = stored;
          applyTheme(theme);
        } else if (mql && mql.matches) {
          theme = 'dark';
          applyTheme(theme);
        } else {
          theme = 'light';
          applyTheme(theme);
        }

        // Listen to system changes (optional)
        if (mql && typeof mql.addEventListener === 'function') {
          mql.addEventListener('change', (ev) => {
            // If persistence is disabled, follow system change
            if (persistence === 'none') {
              const sys = ev.matches ? 'dark' : 'light';
              applyTheme(sys);
            }
          });
        }

        return {
          getTheme() { return theme; },

          setTheme(t) {
            if (t !== 'dark' && t !== 'light') {
              console.warn('ThemeManager.setTheme: invalid theme', t);
              return;
            }
            applyTheme(t);
            if (persistence === 'local') {
              try { localStorage.setItem(STORAGE_KEY, t); } catch (e) {}
            }
          },

          toggle() {
            this.setTheme(theme === 'dark' ? 'light' : 'dark');
          },

          subscribe(fn) {
            if (typeof fn !== 'function') throw new Error('Subscriber must be a function');
            subscribers.add(fn);
            // Immediately call with current theme
            try { fn(theme); } catch (e) { console.error(e); }
            return () => subscribers.delete(fn);
          },

          setPersistence(mode) {
            if (mode !== 'none' && mode !== 'local') {
              throw new Error('Unknown persistence mode: ' + mode);
            }
            persistence = mode;
            if (mode === 'local') {
              try { localStorage.setItem(STORAGE_KEY, theme); } catch (e) {}
            } else {
              try { localStorage.removeItem(STORAGE_KEY); } catch (e) {}
            }
          },

          resetToSystem() {
            const sys = (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) ? 'dark' : 'light';
            persistence = 'none';
            try { localStorage.removeItem(STORAGE_KEY); } catch (e) {}
            applyTheme(sys);
          },

          // exposed for debugging only
          __internal: {
            subscribersCount() { return subscribers.size; },
          }
        };
      }

      return {
        getInstance() {
          if (!instance) {
            instance = createInstance();
          }
          return instance;
        }
      };
    })();

    // ---------------------------------------------------------
    // Wiring the UI to the ThemeManager singleton
    // ---------------------------------------------------------
    (function init() {
      const manager = ThemeManager.getInstance();

      // UI elements
      const toggleBtn = document.getElementById('toggleBtn');
      const themeLabel = document.getElementById('themeLabel');
      const currentThemeText = document.getElementById('currentThemeText');
      const darkBtn = document.getElementById('darkBtn');
      const lightBtn = document.getElementById('lightBtn');
      const persistSelect = document.getElementById('persist');
      const storageStatus = document.getElementById('storageStatus');
      const resetBtn = document.getElementById('resetBtn');
      const systemPref = document.getElementById('systemPref');
      const saveBtn = document.getElementById('saveBtn');

      // Reflect initial system preference
      function updateSystemPrefDisplay() {
        const isDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
        systemPref.textContent = isDark ? 'Dark' : 'Light';
      }
      updateSystemPrefDisplay();
      if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').addEventListener) {
        window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', updateSystemPrefDisplay);
      }

      // Subscribe to theme changes
      manager.subscribe((t) => {
        themeLabel.innerHTML = 'Theme: <strong>' + capitalize(t) + '</strong>';
        currentThemeText.textContent = capitalize(t);
        toggleBtn.setAttribute('aria-pressed', t === 'dark' ? 'true' : 'false');
      });

      // Buttons
      toggleBtn.addEventListener('click', () => {
        manager.toggle();
      });
      darkBtn.addEventListener('click', () => manager.setTheme('dark'));
      lightBtn.addEventListener('click', () => manager.setTheme('light'));
      resetBtn.addEventListener('click', () => {
        manager.resetToSystem();
        persistSelect.value = 'none';
        storageStatus.textContent = 'Not saved';
      });

      // Persistence
      persistSelect.addEventListener('change', () => {
        const val = persistSelect.value;
        manager.setPersistence(val === 'local' ? 'local' : 'none');
        storageStatus.textContent = val === 'local' ? 'Saved to localStorage' : 'Not saved';
      });

      // Simulate saving data to show interactivity
      saveBtn.addEventListener('click', () => {
        const name = document.getElementById('name').value || '(empty)';
        alert('Pretend to save: ' + name + '\\nCurrent theme: ' + capitalize(manager.getTheme()));
      });

      // Update initial UI persistence state based on localStorage
      try {
        const ls = localStorage.getItem('theme-manager:theme');
        if (ls === 'dark' || ls === 'light') {
          persistSelect.value = 'local';
          storageStatus.textContent = 'Saved to localStorage';
          manager.setPersistence('local');
        } else {
          persistSelect.value = 'none';
          storageStatus.textContent = 'Not saved';
        }
      } catch (e) {
        persistSelect.value = 'none';
        storageStatus.textContent = 'Not saved';
      }

      // tiny helper
      function capitalize(s) { return s.charAt(0).toUpperCase() + s.slice(1); }

    })();

    // Expose ThemeManager globally for testing in console (optional)
    window.ThemeManager = ThemeManager;

  </script>
</body>
</html>
```

Notes:
- The ThemeManager is implemented as a JavaScript IIFE that returns an object with getInstance — ensuring only one instance is created.
- The singleton includes subscribe/unsubscribe semantics so multiple components can react to changes.
- Persistence to localStorage is optional; you can enable it from the "Preferences" select.
- The "Singleton: Pros & Cons" section is visible on the page, and the text explains when DI is preferable.

