  <script>
    // The "Singleton" state manager pattern (naive, self-contained)
    // We create an IIFE that returns a single instance with state, listeners, and simple persistence.
    const ThemeSingleton = (function () {
      // Private variables — only one instance created by this closure
      let instance;

      function createInstance() {
        // state
        const state = {
          theme: (localStorage.getItem('app-theme')) || 'light'
        };

        // simple publish/subscribe
        const listeners = new Set();

        function notify() {
          listeners.forEach(fn => {
            try { fn(state); } catch (e) { console.error('Listener error', e); }
          });
        }

        // initialize DOM root class
        const root = document.documentElement;
        function applyThemeToRoot() {
          if (state.theme === 'dark') root.classList.add('dark');
          else root.classList.remove('dark');
        }
        applyThemeToRoot();

        return {
          getTheme() { return state.theme; },
          setTheme(t) {
            if (t !== 'light' && t !== 'dark') return;
            if (state.theme === t) return;
            state.theme = t;
            localStorage.setItem('app-theme', t);
            applyThemeToRoot();
            notify();
          },
          toggle() {
            this.setTheme(state.theme === 'dark' ? 'light' : 'dark');
          },
          subscribe(fn) { listeners.add(fn); return () => listeners.delete(fn); },
          // for debugging
          _debugState() { return { ...state }; }
        };
      }

      return {
        getInstance() {
          if (!instance) instance = createInstance();
          return instance;
        }
      };
    })();

    // Usage: multiple parts of the app obtain the same instance
    const theme = ThemeSingleton.getInstance();

    // Render controls
    (function renderControls() {
      const container = document.getElementById('controls');

      const lightBtn = document.createElement('button');
      lightBtn.textContent = 'Light';
      lightBtn.onclick = () => theme.setTheme('light');

      const darkBtn = document.createElement('button');
      darkBtn.textContent = 'Dark';
      darkBtn.onclick = () => theme.setTheme('dark');

      const toggleBtn = document.createElement('button');
      toggleBtn.textContent = 'Toggle';
      toggleBtn.onclick = () => theme.toggle();

      container.appendChild(lightBtn);
      container.appendChild(darkBtn);
      container.appendChild(toggleBtn);
    })();

    // Components subscribe to the singleton
    function mountComponent(id, badgeId) {
      const el = document.getElementById(id);
      const badge = document.getElementById(badgeId);

      function render(s) {
        badge.textContent = s.theme;
        // optionally style the card border or background based on theme
        if (s.theme === 'dark') {
          el.style.boxShadow = '0 1px 8px rgba(0,0,0,0.6)';
        } else {
          el.style.boxShadow = '0 1px 0 rgba(0,0,0,0.04)';
        }
      }

      // initial render
      render({ theme: theme.getTheme() });

      // subscribe to future changes
      const unsub = theme.subscribe(render);
      // return an unmount function in case we wanted to remove the component
      return unsub;
    }

    mountComponent('cardA', 'themeA');
    mountComponent('cardB', 'themeB');
    mountComponent('cardC', 'themeC');
    // cardD shows persistence info only

