            subscribe(fn) {
              if (typeof fn !== 'function') return;
              subscribers.add(fn);
              // send immediate current state
              try { fn({ theme }); } catch (e) { console.error('Subscriber init error', e); }
            },
            unsubscribe(fn) {
              subscribers.delete(fn);
            }
          };
        }

        return {
          getInstance() {
            if (!instance) instance = createInstance();
            return instance;
          }
        };
      })();

      // expose to global so components can access
      global.ThemeManager = ThemeManager;
    })(window);

    // ---- Example usage across multiple elements ----

    const manager = ThemeManager.getInstance();

    // UI wiring
    const toggleBtn = document.getElementById('toggle-btn');
    const chip1 = document.getElementById('chip-1');
    const chip2 = document.getElementById('chip-2');
    const statusDot = document.getElementById('status-dot');
    const statusText = document.getElementById('status-text');
    const accentSample = document.getElementById('accent-sample');
    const componentText = document.getElementById('component-text');
    const makeDark = document.getElementById('make-dark');
    const makeLight = document.getElementById('make-light');

    toggleBtn.addEventListener('click', () => manager.toggle());
    chip1.addEventListener('click', () => alert('Chip 1 clicked\n(current theme: ' + manager.getTheme() + ')'));
    chip2.addEventListener('click', () => alert('Chip 2 clicked\n(current theme: ' + manager.getTheme() + ')'));
    makeDark.addEventListener('click', () => manager.set('dark'));
    makeLight.addEventListener('click', () => manager.set('light'));

    // Subscriber that updates multiple elements whenever theme changes
    function onThemeChange(payload) {
      const t = payload.theme;
      statusText.textContent = 'Status: ' + (t === 'dark' ? 'Dark' : 'Light');
      // visually tweak the status dot
      if (t === 'dark') {
        statusDot.style.borderColor = 'var(--accent)';
        statusDot.style.background = 'var(--bg)';
      } else {
        statusDot.style.borderColor = 'var(--accent)';
        statusDot.style.background = 'var(--bg)';
      }
      // change some sample text
      accentSample.textContent = t === 'dark' ? 'Dark accent' : 'Light accent';
      componentText.textContent = 'Current theme is ' + t + '. Components update automatically via subscription.';
      // reflect toggle button label
      toggleBtn.textContent = (t === 'dark') ? 'Switch to Light' : 'Switch to Dark';
    }

    // Subscribe multiple components (simulating many consumers)
    manager.subscribe(onThemeChange);

    // Another subscriber attached directly to update aria attributes or analytics
    function accessibilitySubscriber({ theme }) {
      document.body.setAttribute('data-theme', theme);
      // Example: an analytics hook could be placed here (omitted)
    }
    manager.subscribe(accessibilitySubscriber);

    // Demonstrate unsubscribe after a while (not necessary, but shows API)
    // After 30s we remove the accessibility subscriber
    setTimeout(() => manager.unsubscribe(accessibilitySubscriber), 30000);
  </script>
</body>
</html>

Why singletons are often terrible (short summary)
- Hidden global state: Singletons are effectively globals. Code that uses them depends on shared, hidden state, making reasoning and testing harder.
- Tight coupling: Consumers become coupled to the singleton's concrete implementation and its global access, reducing modularity.
- Difficult testing: Because singletons hold global state, tests can leak state between cases; mocking requires additional effort or hacks.
- Order and lifecycle issues: Initialization order matters; lazy initialization can hide bugs. Hard to manage cleanup.
- Reduced composability: With a singleton it's harder to run multiple independent instances (e.g., two theme contexts on the same page) or to run isolated instances for parallel tests.
- Impedes dependency injection: Singleton usage encourages retrieving dependencies inside modules instead of receiving them via constructor/args, which harms clarity and flexibility.

Better alternatives
- Explicit dependency injection: Pass specific instances (theme manager, config, logger) into components that need them. This makes dependencies explicit and testable.
- Context objects/providers: In UI libraries (React, Vue, etc.), use context/provider patterns to scope state to a subtree rather than global scope.
- Factory functions: Create instances with controlled lifecycle and pass them where needed. Factories can create multiple independent instances when useful.
- Event emitters / pub-sub instances: Instead of a single global instance, create an event bus that you can instantiate per domain, and pass it to consumers.
- State containers with clear APIs: Use well-scoped state containers (e.g., Redux stores, Zustand stores, Vuex) that are injected or provided explicitly; they often include tooling for testing and time-travel.
- Functional approaches: Prefer pure functions and immutable state transitions where possible; keep side effects isolated and explicit.

When a singleton might be acceptable
- Truly global, unchanging resources (e.g., a cross-cutting audit logger) can be pragmatic as a singleton if used cautiously and wrapped for testability.
- But even then, prefer to wrap the singleton behind an interface so tests can inject a fake.

